class Solution:
    def canPartition(self, nums: list[int]) -> bool:
        s = sum(nums)
        if s & 1:                    # 总和为奇,无法平分
            return False
        target = s // 2
        f = [False] * (target + 1)   # f[v]:能否凑出和为 v 的子集
        f[0] = True                  # 空集凑出 0
        for x in nums:
            for v in range(target, x - 1, -1):   # 倒序!保证每个数只用一次(0-1 背包)
                f[v] = f[v] or f[v - x]
        return f[target]
